mapper.select:
SELECT W.warehouse_no warehouseNo ,warehouse_name warehouseName,storage_spaces_no binCode,storage_spaces_name binName FROM srm_bar_stor_head W LEFT JOIN srm_bar_stor_body B ON W.warehouse_no = B.warehouse_no
AND W.warehouse_no = #{warehouseNo}
AND W.warehouse_name LIKE {warehouseName}+'%'
AND B.storage_spaces_no = #{binCode}
AND B.storage_spaces_name LIKE #{binName}+'%'
